mapper.select:
SELECT t.id, t.template_name, t.report_type, t.content_template, t.is_default, t.is_enable, t.remark, t.create_time, u.nick_name AS createUserName FROM tb_report_template t LEFT JOIN tb_user u ON t.create_user_id = u.id AND u.is_deleted = 0 WHERE t.is_deleted = 0
AND t.template_name LIKE CONCAT('%', #{dto.templateName}, '%')
AND t.report_type = #{dto.reportType}
AND t.is_enable = #{dto.isEnable}
ORDER BY t.id DESC
